import type { Prisma } from "@prisma/client";

/**
 * Prisma where-clause for the "Sport 2.0" pipeline.
 * All events generated by the Football Intelligence Engine (FIE) have sourceType = "SPORT".
 */
export const SPORT_20_PIPELINE_WHERE: Prisma.EventWhereInput = {
  sourceType: "SPORT",
};

/**
 * Full where-clause for active sport 2.0 events (used in homepage sections).
 */
export const ACTIVE_SPORT_20_WHERE: Prisma.EventWhereInput = {
  sourceType: "SPORT",
  hidden: false,
  status: "OPEN",
  resolved: false,
};

/**
 * Returns true if the event was generated by the Sport 2.0 pipeline.
 */
export function isSport20Event(event: { sourceType?: string | null }): boolean {
  return event.sourceType === "SPORT";
}

/**
 * Match statuses that indicate a live/in-progress match.
 */
export const LIVE_MATCH_STATUSES = new Set(["IN_PLAY", "PAUSED"]);

/**
 * Returns true if the event's match is currently live.
 */
export function isLiveMatch(event: { matchStatus?: string | null }): boolean {
  return LIVE_MATCH_STATUSES.has(event.matchStatus ?? "");
}

/**
 * Returns true if a market is "unique" (creative, not a standard match-result market).
 * Unique markets are those that don't follow the "Team A vs Team B" result pattern
 * or involve unusual/creative questions about the match.
 */
export function isUniqueMarket(title: string): boolean {
  const t = title.toLowerCase();
  const isStandardVsMatch = t.includes(" vs ") || t.includes(" v ");
  if (!isStandardVsMatch) return true;

  const creativeKeywords = [
    "espuls",
    "var ",
    "rigore",
    "reti ",
    "assist",
    "ammon",
    "trending",
    "hashtag",
    "social",
    "celebra",
    "siuu",
    "hattrick",
    "hat-trick",
    "capocannoniere",
    "mvp",
    "penalty",
    "cartellino",
  ];
  return creativeKeywords.some((kw) => t.includes(kw));
}

/**
 * Competition slugs for the calendar filter tabs.
 */
export const COMPETITION_FILTERS = [
  { label: "Tutti", value: "all" },
  { label: "Serie A", value: "serie-a" },
  { label: "Champions", value: "champions-league" },
  { label: "Premier", value: "premier-league" },
  { label: "Liga", value: "la-liga" },
] as const;

export type CompetitionFilterValue = (typeof COMPETITION_FILTERS)[number]["value"];

/**
 * Normalizes a sport league name to a competition filter value.
 */
export function getCompetitionFilter(sportLeague?: string | null): CompetitionFilterValue {
  if (!sportLeague) return "all";
  const l = sportLeague.toLowerCase();
  if (l.includes("serie a") || l.includes("serie-a")) return "serie-a";
  if (l.includes("champions") || l.includes("ucl")) return "champions-league";
  if (l.includes("premier")) return "premier-league";
  if (l.includes("liga") || l.includes("laliga")) return "la-liga";
  return "all";
}
